static int em_check_suspicious_ae(const char *ae) {
    if (ae == NULL || ae[0] == '\0')
        return 0;
    /* Check for known attacker AE Title patterns */
    const char *suspicious[] = {
        "ATTACKER", "EVIL", "EXFIL", "ROGUE",
        "HACKER", "MALICIOUS", "UNKNOWN_DEST"
    };
    int n = sizeof(suspicious) / sizeof(suspicious[0]);
    int i;
    for (i = 0; i < n; i++) {
        if (strstr(ae, suspicious[i]) != NULL)
            return 1;
    }
    /* Check for non-alphanumeric characters (invalid per DICOM standard) */
    const char *p = ae;
    while (*p) {
        if (*p != ' ' && *p != '_' &&
            !(*p >= 'A' && *p <= 'Z') &&
            !(*p >= 'a' && *p <= 'z') &&
            !(*p >= '0' && *p <= '9')) {
            return 1;
        }
        p++;
    }
    return 0;
}
